     8→	"github.com/jackc/pgx/v5/pgxpool"
     9→)
    10→
    11→// Orchestrator runs polling ingestion sources on a fixed interval.
    12→type Orchestrator struct {
    13→	service       *Service
    14→	loader        *SourceLoader
    15→	pool          *pgxpool.Pool
    16→	staticSources []IIngestionSource // for testing only
    17→	interval      time.Duration
    18→}
    19→
    20→// NewOrchestrator creates an orchestrator that dynamically loads enabled
    21→// sources from the database on each poll cycle.
    22→func NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
    23→	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
    24→}
    25→
    26→// NewOrchestratorWithSources creates an orchestrator with a static source list.
    27→// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
    28→func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
    29→	return &Orchestrator{service: service, staticSources: sources, interval: interval}
    30→}
    31→
    32→// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
    33→func (o *Orchestrator) Run(ctx context.Context) {
    34→	ticker := time.NewTicker(o.interval)
    35→	defer ticker.Stop()
    36→
    37→	o.pollAll(ctx)
    38→
    39→	for {
    40→		select {
    41→		case <-ctx.Done():
    42→			return
    43→		case <-ticker.C:
    44→			o.pollAll(ctx)
    45→		}
    46→	}
    47→}
    48→
    49→func (o *Orchestrator) pollAll(ctx context.Context) {
    50→	sources := o.staticSources
    51→	if sources == nil {
    52→		var err error
    53→		sources, err = o.loader.LoadEnabledSources(ctx)
    54→		if err != nil {
    55→			slog.Error("load sources failed", "err", err)
    56→			return
    57→		}
    58→	}
    59→	if len(sources) == 0 {
    60→		slog.Debug("no enabled sources to poll")
    61→		return
    62→	}
    63→	for _, src := range sources {
    64→		results, err := src.FetchNewReleases(ctx)
    65→		if err != nil {
    66→			slog.Error("poll failed", "source", src.Name(), "err", err)
    67→			o.updateSourcePollStatus(ctx, src.SourceID(), err)
    68→			continue
    69→		}
    70→		o.updateSourcePollStatus(ctx, src.SourceID(), nil)
    71→		if len(results) == 0 {
    72→			continue
    73→		}
    74→		if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
    75→			slog.Error("process failed", "source", src.Name(), "err", err)
    76→		}
    77→	}
    78→}
    79→
    80→func (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
    81→	if o.pool == nil {
    82→		return
    83→	}
    84→	var lastError *string
    85→	if pollErr != nil {
    86→		s := pollErr.Error()
    87→		lastError = &s
    88→	}
    89→	_, err := o.pool.Exec(ctx,
    90→		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
    91→		lastError, sourceID)
    92→	if err != nil {
    93→		slog.Error("update source poll status", "source", sourceID, "err", err)
    94→	}
    95→}
